def create_signed_message(job_id: str, job_type: str, payload: dict,
                          priority: int = 0, metadata: dict = None) -> tuple:
    """
    Utility function for message producers to create properly signed messages.

    Returns (message_body_json, signature) tuple.
    """
    signing_key = os.environ.get("MESSAGE_SIGNING_KEY")
    if not signing_key:
        raise RuntimeError("MESSAGE_SIGNING_KEY not configured")

    message_data = {
        "job_id": job_id,
        "job_type": job_type,
        "payload": payload,
        "priority": priority,
        "metadata": metadata or {},
    }

    message_body = json.dumps(message_data, sort_keys=True)

    signature = hmac.new(
        signing_key.encode("utf-8"),
        message_body.encode("utf-8"),
        hashlib.sha256,
    ).hexdigest()

    return message_body, signature